14	use clap::Parser;
15	use git_version::git_version;
16	use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};
17	use zenoh::{config::WhatAmI, Config, Result, Wait};
18	use zenoh_config::{EndPoint, EndPoints, ModeDependentValue, PermissionsConf};
19	use zenoh_util::LibSearchDirs;
