21	const GIT_VERSION: &str = git_version!(prefix = "v", cargo_prefix = "v");
22	
23	lazy_static::lazy_static!(
24	    static ref LONG_VERSION: String = format!("{} built with {}", GIT_VERSION, env!("RUSTC_VERSION"));
25	);
26	
27	#[derive(Debug, Parser)]
28	#[command(version=GIT_VERSION, long_version=LONG_VERSION.as_str(), about="The zenoh router")]
29	struct Args {
30	    /// The configuration file. Currently, this file must be a valid JSON5 or YAML file.
31	    #[arg(short, long, value_name = "PATH")]
32	    config: Option<String>,
33	    /// Locators on which this router will listen for incoming sessions. Repeat this option to open several listeners.
34	    #[arg(short, long, value_name = "ENDPOINT")]
35	    listen: Vec<String>,
36	    /// A peer locator this router will try to connect to.
37	    /// Repeat this option to connect to several peers.
38	    #[arg(short = 'e', long, value_name = "ENDPOINT")]
39	    connect: Vec<String>,
40	    /// The identifier (as an hexadecimal string, with odd number of chars - e.g.: A0B23...) that zenohd must use. If not set, a random unsigned 128bit integer will be used.
41	    /// WARNING: this identifier must be unique in the system and must be 16 bytes maximum (32 chars)!
42	    #[arg(short, long)]
43	    id: Option<String>,
44	    /// A plugin that MUST be loaded. You can give just the name of the plugin, zenohd will search for a library named 'libzenoh_plugin_\<name\>.so' (exact name depending the OS). Or you can give such a string: "\<plugin_name\>:\<library_path\>"
45	    /// Repeat this option to load several plugins. If loading failed, zenohd will exit.
46	    #[arg(short = 'P', long)]
47	    plugin: Vec<String>,
48	    /// Directory where to search for plugins libraries to load.
49	    /// Repeat this option to specify several search directories.
50	    #[arg(long, value_name = "PATH")]
51	    plugin_search_dir: Vec<String>,
52	    /// By default zenohd adds a HLC-generated Timestamp to each routed Data if there isn't already one. This option disables this feature.
53	    #[arg(long)]
54	    no_timestamp: bool,
55	    /// By default zenohd replies to multicast scouting messages for being discovered by peers and clients. This option disables this feature.
56	    #[arg(long)]
57	    no_multicast_scouting: bool,
58	    /// Enables REST API plugin and configures HTTP interface for it. Accepted values:
59	    ///   - a port number
60	    ///   - a string with format `<local_ip>:<port_number>` (to bind the HTTP server to a specific interface)
61	    #[arg(long, value_name = "SOCKET")]
62	    rest_http_port: Option<String>,
63	    /// Allows arbitrary configuration changes as column-separated KEY:VALUE pairs,
64	    /// where the empty key is used to represent the entire configuration:
65	    ///   - KEY must be a valid config path, or empty string if the whole configuration is defined.
66	    ///   - VALUE must be a valid JSON5 string that can be deserialized to the expected type for the KEY field.
67	    ///
68	    /// Examples:
69	    /// - `--cfg='startup/subscribe:["demo/**"]'`
70	    /// - `--cfg='plugins/storage_manager/storages/demo:{key_expr:"demo/example/**",volume:"memory"}'`
71	    /// - `--cfg=':{metadata:{name:"My App"},adminspace:{enabled:true,permissions:{read:true,write:true}}'`
72	    #[arg(long)]
73	    cfg: Vec<String>,
74	    /// Configure the read and/or write permissions on the admin space. Default is read only.
75	    #[arg(long, value_name = "[r|w|rw|none]")]
76	    adminspace_permissions: Option<String>,
77	}
78	
79	fn main() {
80	    if let Err(e) = init_logging() {
81	        eprintln!("{e}. Exiting...");
82	        std::process::exit(-1);
83	    }
84	
85	    tracing::info!("zenohd {}", *LONG_VERSION);
86	
87	    let args = Args::parse();
88	    let config = config_from_args(&args);
89	    tracing::info!("Initial conf: {}", &config);
90	
91	    let _session = match zenoh::open(config).wait() {
92	        Ok(runtime) => runtime,
93	        Err(e) => {
94	            eprintln!("{e}. Exiting...");
95	            std::process::exit(-1);
96	        }
97	    };
98	
99	    std::thread::park();
100	}
