102	fn config_from_args(args: &Args) -> Config {
103	    let mut inline_config = None;
104	    for json in &args.cfg {
105	        if let Some(("", cfg)) = json.split_once(':') {
106	            inline_config = Some(cfg);
107	        }
108	    }
109	
110	    let mut config = if let Some(cfg) = inline_config {
111	        Config::from_json5(cfg).expect("Invalid Zenoh config")
112	    } else if let Some(fname) = args.config.as_ref() {
113	        Config::from_file(fname).expect("Failed to load config file")
114	    } else {
115	        Config::default()
116	    };
117	
118	    if config.mode().is_none() {
119	        config.set_mode(Some(WhatAmI::Router)).unwrap();
120	    }
121	    if let Some(id) = &args.id {
122	        config.set_id(Some(id.parse().unwrap())).unwrap();
123	    }
124	    // apply '--rest-http-port' to config only if explicitly set (overwriting config)
125	    if args.rest_http_port.is_some() {
126	        let value = args.rest_http_port.as_deref().unwrap_or("8000");
127	        if !value.eq_ignore_ascii_case("none") {
128	            config
129	                .insert_json5("plugins/rest/http_port", &format!(r#""{value}""#))
130	                .unwrap();
131	            config
132	                .insert_json5("plugins/rest/__required__", "true")
133	                .unwrap();
134	        }
135	    }
136	    config.adminspace.set_enabled(true).unwrap();
137	    config.plugins_loading.set_enabled(true).unwrap();
138	    if !args.plugin_search_dir.is_empty() {
139	        config
140	            .plugins_loading
141	            // REVIEW: Should this append to search_dirs instead? As there is no way to pass the new
142	            // `current_exe_parent` unless we change the format of the argument and this overrides
143	            // the one set from the default config. 
144	            // Also, --cfg plugins_loading/search_dirs=[...] makes this argument superfluous.
145	            .set_search_dirs(LibSearchDirs::from_paths(&args.plugin_search_dir))
146	            .unwrap();
147	    }
148	    for plugin in &args.plugin {
149	        match plugin.split_once(':') {
150	            Some((name, path)) => {
151	                config
152	                    .insert_json5(&format!("plugins/{name}/__required__"), "true")
153	                    .unwrap();
154	                config
155	                    .insert_json5(&format!("plugins/{name}/__path__"), &format!("\"{path}\""))
156	                    .unwrap();
157	            }
158	            None => config
159	                .insert_json5(&format!("plugins/{plugin}/__required__"), "true")
160	                .unwrap(),
161	        }
162	    }
163	    if !args.connect.is_empty() {
164	        config
165	            .connect
166	            .endpoints
167	            .set(
168	                args.connect
169	                    .iter()
170	                    .map(|v| match v.parse::<EndPoints>() {
171	                        Ok(v) => v,
172	                        Err(e) => {
173	                            panic!("Couldn't parse option --peer={v} into Locator: {e}");
174	                        }
175	                    })
176	                    .collect(),
177	            )
178	            .unwrap();
179	    }
180	    if !args.listen.is_empty() {
181	        config
182	            .listen
183	            .endpoints
184	            .set(
185	                args.listen
186	                    .iter()
187	                    .map(|v| match v.parse::<EndPoint>() {
188	                        Ok(v) => v,
189	                        Err(e) => {
190	                            panic!("Couldn't parse option --listen={v} into Locator: {e}");
191	                        }
192	                    })
193	                    .collect(),
194	            )
195	            .unwrap();
196	    }
197	    if args.no_timestamp {
198	        config
199	            .timestamping
200	            .set_enabled(Some(ModeDependentValue::Unique(false)))
201	            .unwrap();
202	    };
203	    match (
204	        config.scouting.multicast.enabled().is_none(),
205	        args.no_multicast_scouting,
206	    ) {
207	        (_, true) => {
208	            config.scouting.multicast.set_enabled(Some(false)).unwrap();
209	        }
210	        (true, false) => {
211	            config.scouting.multicast.set_enabled(Some(true)).unwrap();
212	        }
213	        (false, false) => {}
214	    };
215	    if let Some(adminspace_permissions) = &args.adminspace_permissions {
216	        match adminspace_permissions.as_str() {
217	            "r" => config
218	                .adminspace
219	                .set_permissions(PermissionsConf {
220	                    read: true,
221	                    write: false,
222	                })
223	                .unwrap(),
224	            "w" => config
225	                .adminspace
226	                .set_permissions(PermissionsConf {
227	                    read: false,
228	                    write: true,
229	                })
230	                .unwrap(),
231	            "rw" => config
232	                .adminspace
233	                .set_permissions(PermissionsConf {
234	                    read: true,
235	                    write: true,
236	                })
237	                .unwrap(),
238	            "none" => config
239	                .adminspace
240	                .set_permissions(PermissionsConf {
241	                    read: false,
242	                    write: false,
243	                })
244	                .unwrap(),
245	            s => panic!(
246	                r#"Invalid option: --adminspace-permissions={s} - Accepted values: "r", "w", "rw" or "none""#
247	            ),
248	        };
249	    }
250	    for json in &args.cfg {
251	        if let Some((key, value)) = json.split_once(':') {
252	            if !key.is_empty() {
253	                match json5::Deserializer::from_str(value) {
254	                    Ok(mut deserializer) => {
255	                        if let Err(e) =
256	                            config.insert(key.strip_prefix('/').unwrap_or(key), &mut deserializer)
257	                        {
258	                            tracing::warn!("Couldn't perform configuration {}: {}", json, e);
259	                        }
260	                    }
261	                    Err(e) => tracing::warn!("Couldn't perform configuration {}: {}", json, e),
262	                }
263	            }
264	        } else {
265	            panic!("--cfg accepts KEY:VALUE pairs. {json} is not a valid KEY:VALUE pair.")
266	        }
267	    }
268	    tracing::debug!("Config: {:?}", &config);
269	    config
270	}
271	
272	fn init_logging() -> Result<()> {
273	    let env_filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("z=info"));
274	
275	    let fmt_layer = tracing_subscriber::fmt::Layer::new()
276	        .with_thread_ids(true)
277	        .with_thread_names(true)
278	        .with_level(true)
279	        .with_target(true);
280	
281	    let tracing_sub = tracing_subscriber::registry()
282	        .with(env_filter)
283	        .with(fmt_layer);
284	
285	    tracing_sub.init();
286	    Ok(())
287	}
