144	    /// Adds a statically linked plugin to the manager.
145	    pub fn declare_static_plugin<
146	        P: Plugin<StartArgs = StartArgs, Instance = Instance> + Send + Sync,
147	        S: Into<String>,
148	    >(
149	        &mut self,
150	        id: S,
151	        required: bool,
152	    ) {
153	        let id = id.into();
154	        let plugin_loader: StaticPlugin<StartArgs, Instance, P> =
155	            StaticPlugin::new(id.clone(), required);
156	
157	        if self.get_plugin_index(&id).is_some() {
158	            tracing::warn!(
159	                "Duplicate plugin with ID: {id}, only the last declared one will be loaded"
160	            )
161	        }
162	
163	        self.plugins.push(PluginRecord::new(plugin_loader));
164	        tracing::debug!(
165	            "Declared static plugin Id:{} - Name:{}",
166	            self.plugins.last().unwrap().id(),
167	            self.plugins.last().unwrap().name()
168	        );
169	    }
