171	    /// Add dynamic plugin to the manager by name, automatically prepending the default library prefix
172	    pub fn declare_dynamic_plugin_by_name<S: Into<String>>(
173	        &mut self,
174	        id: S,
175	        plugin_name: S,
176	        required: bool,
177	    ) -> ZResult<&mut dyn DeclaredPlugin<StartArgs, Instance>> {
178	        let plugin_name = plugin_name.into();
179	        let id = id.into();
180	        let libplugin_name = format!("{}{}", self.default_lib_prefix, plugin_name);
181	        let libloader = self
182	            .loader
183	            .as_ref()
184	            .ok_or("Dynamic plugin loading is disabled")?
185	            .clone();
186	        tracing::debug!(
187	            "Declared dynamic plugin {} by name {}",
188	            &id,
189	            &libplugin_name
190	        );
191	        let loader = DynamicPlugin::new(
192	            plugin_name,
193	            id.clone(),
194	            DynamicPluginSource::ByName((libloader, libplugin_name)),
195	            required,
196	        );
197	
198	        if self.get_plugin_index(&id).is_some() {
199	            tracing::warn!(
200	                "Duplicate plugin with ID: {id}, only the last declared one will be loaded"
201	            )
202	        }
203	        self.plugins.push(PluginRecord::new(loader));
204	        Ok(self.plugins.last_mut().unwrap())
205	    }
