207	    /// Add first available dynamic plugin from the list of paths to the plugin files
208	    pub fn declare_dynamic_plugin_by_paths<S: Into<String>, P: AsRef<str> + std::fmt::Debug>(
209	        &mut self,
210	        name: S,
211	        id: S,
212	        paths: &[P],
213	        required: bool,
214	    ) -> ZResult<&mut dyn DeclaredPlugin<StartArgs, Instance>> {
215	        let name = name.into();
216	        let id = id.into();
217	        let paths = paths.iter().map(|p| p.as_ref().into()).collect();
218	        tracing::debug!("Declared dynamic plugin {} by paths {:?}", &id, &paths);
219	        let loader = DynamicPlugin::new(
220	            name,
221	            id.clone(),
222	            DynamicPluginSource::ByPaths(paths),
223	            required,
224	        );
225	
226	        if self.get_plugin_index(&id).is_some() {
227	            tracing::warn!(
228	                "Duplicate plugin with ID: {id}, only the last declared one will be loaded"
229	            )
230	        }
231	
232	        self.plugins.push(PluginRecord::new(loader));
233	        Ok(self.plugins.last_mut().unwrap())
234	    }
