327	impl<StartArgs: PluginStartArgs + 'static, Instance: PluginInstance + 'static> PluginControl
328	    for PluginsManager<StartArgs, Instance>
329	{
330	    fn plugins_status(&self, names: &keyexpr) -> Vec<PluginStatusRec<'_>> {
331	        tracing::debug!(
332	            "Plugin manager with prefix `{}` : requested plugins_status {:?}",
333	            self.default_lib_prefix,
334	            names
335	        );
336	        let mut plugins = Vec::new();
337	        for plugin in self.declared_plugins_iter() {
338	            let id = unsafe { keyexpr::from_str_unchecked(plugin.id()) };
339	            if names.includes(id) {
340	                let status = PluginStatusRec::new(plugin.as_status());
341	                plugins.push(status);
342	            }
343	            // for running plugins append their subplugins prepended with the running plugin name
344	            if let Some(plugin) = plugin.loaded() {
345	                if let Some(plugin) = plugin.started() {
346	                    if let [names, ..] = names.strip_prefix(id)[..] {
347	                        plugins.append(
348	                            &mut plugin
349	                                .instance()
350	                                .plugins_status(names)
351	                                .into_iter()
352	                                .map(|s| s.prepend_name(id))
353	                                .collect(),
354	                        );
355	                    }
356	                }
357	            }
358	        }
359	        plugins
360	    }
361	}
