92	#[inline(always)]
93	pub(crate) fn blockon_runtime<F: Future>(task: F) -> F::Output {
94	    // Check whether able to get the current runtime
95	    match tokio::runtime::Handle::try_current() {
96	        Ok(rt) => {
97	            // Able to get the current runtime (standalone binary), use the current runtime
98	            tokio::task::block_in_place(|| rt.block_on(task))
99	        }
100	        Err(_) => {
101	            // Unable to get the current runtime (dynamic plugins), reuse the global runtime
102	            tokio::task::block_in_place(|| TOKIO_RUNTIME.block_on(task))
103	        }
104	    }
105	}
106	
107	pub(crate) fn spawn_runtime<F>(task: F) -> JoinHandle<F::Output>
108	where
109	    F: Future + Send + 'static,
110	    F::Output: Send + 'static,
111	{
112	    // Check whether able to get the current runtime
113	    match tokio::runtime::Handle::try_current() {
114	        Ok(rt) => {
115	            // Able to get the current runtime (standalone binary), spawn on the current runtime
116	            rt.spawn(task)
117	        }
118	        Err(_) => {
119	            // Unable to get the current runtime (dynamic plugins), spawn on the global runtime
120	            TOKIO_RUNTIME.spawn(task)
121	        }
122	    }
123	}
