126	struct JSONSample {
127	    key: String,
128	    value: serde_json::Value,
129	    encoding: String,
130	    timestamp: Option<String>,
131	}
132	
133	impl JSONSample {
134	    fn new(
135	        key: impl Into<String>,
136	        payload: &ZBytes,
137	        encoding: &Encoding,
138	        timestamp: Option<&Timestamp>,
139	    ) -> Self {
140	        JSONSample {
141	            key: key.into(),
142	            value: Self::payload_to_json(payload, encoding),
143	            encoding: encoding.to_string(),
144	            timestamp: timestamp.map(|ts| ts.to_string()),
145	        }
146	    }
147	
148	    fn payload_to_json(payload: &ZBytes, encoding: &Encoding) -> serde_json::Value {
149	        if payload.is_empty() {
150	            return serde_json::Value::Null;
151	        }
152	        let base64_encode = |data: &[u8]| base64::engine::general_purpose::STANDARD.encode(data);
153	        match encoding {
154	            // If it is a JSON try to deserialize as json, if it fails fallback to base64
155	            &Encoding::APPLICATION_JSON | &Encoding::TEXT_JSON | &Encoding::TEXT_JSON5 => {
156	                let bytes = payload.to_bytes();
157	                serde_json::from_slice(&bytes).unwrap_or_else(|e| {
158	                    tracing::warn!(
159	                        "Encoding is JSON but data is not JSON, converting to base64, Error: {e:?}"
160	                    );
161	                    serde_json::Value::String(base64_encode(&bytes))
162	                })
163	            }
164	            &Encoding::TEXT_PLAIN | &Encoding::ZENOH_STRING => serde_json::Value::String(
165	                String::from_utf8(payload.to_bytes().into_owned()).unwrap_or_else(|e| {
166	                    tracing::warn!(
167	                    "Encoding is String but data is not String, converting to base64, Error: {e:?}"
168	                );
169	                    base64_encode(e.as_bytes())
170	                }),
171	            ),
172	            // otherwise convert to JSON string
173	            _ => serde_json::Value::String(base64_encode(&payload.to_bytes())),
174	        }
175	    }
176	}
