197	impl Plugin for RestPlugin {
198	    type StartArgs = DynamicRuntime;
199	    type Instance = zenoh::internal::plugins::RunningPlugin;
200	    const DEFAULT_NAME: &'static str = "rest";
201	    const PLUGIN_VERSION: &'static str = plugin_version!();
202	    const PLUGIN_LONG_VERSION: &'static str = plugin_long_version!();
203	
204	    fn start(
205	        name: &str,
206	        runtime: &Self::StartArgs,
207	    ) -> ZResult<zenoh::internal::plugins::RunningPlugin> {
208	        // Try to initiate login.
209	        // Required in case of dynamic lib, otherwise no logs.
210	        // But cannot be done twice in case of static link.
211	        zenoh::init_log_from_env_or("error");
212	        tracing::debug!("REST plugin {}", LONG_VERSION.as_str());
213	
214	        let plugin_conf = runtime
215	            .get_config()
216	            .get_plugin_config(name)
217	            .map_err(|_| zerror!("Plugin `{}`: missing config", name))?;
218	
219	        let conf: Config = serde_json::from_value(plugin_conf)
220	            .map_err(|e| zerror!("Plugin `{}` configuration error: {}", name, e))?;
221	        WORKER_THREAD_NUM.store(conf.work_thread_num, Ordering::SeqCst);
222	        MAX_BLOCK_THREAD_NUM.store(conf.max_block_thread_num, Ordering::SeqCst);
223	
224	        let task = run(runtime.clone(), conf.addr);
225	        let task =
226	            blockon_runtime(async { timeout(Duration::from_millis(1), spawn_runtime(task)).await });
227	
228	        // The spawn task (spawn_runtime(task)).await) should not return immediately. The server should block inside.
229	        // If it returns immediately (for example, address already in use), we can get the error inside Ok
230	        if let Ok(Ok(Err(e))) = task {
231	            bail!("REST server failed within 1ms: {e}")
232	        }
233	
234	        Ok(Box::new(RunningPlugin(conf)))
235	    }
236	}
