249	        let mut key = String::from(plugin_status_key);
250	        with_extended_string(&mut key, &["/version"], |key| {
251	            if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
252	                responses.push(zenoh::internal::plugins::Response::new(
253	                    key.clone(),
254	                    GIT_VERSION.into(),
255	                ))
256	            }
257	        });
258	        with_extended_string(&mut key, &["/port"], |port_key| {
259	            if keyexpr::new(port_key.as_str())
260	                .unwrap()
261	                .intersects(key_expr)
262	            {
263	                responses.push(zenoh::internal::plugins::Response::new(
264	                    port_key.clone(),
265	                    (&self.0).into(),
266	                ))
267	            }
268	        });
269	        Ok(responses)
270	    }
271	}
