273	fn with_extended_string<R, F: FnMut(&mut String) -> R>(
274	    prefix: &mut String,
275	    suffixes: &[&str],
276	    mut closure: F,
277	) -> R {
278	    let prefix_len = prefix.len();
279	    for suffix in suffixes {
280	        prefix.push_str(suffix);
281	    }
282	    let result = closure(prefix);
283	    prefix.truncate(prefix_len);
284	    result
285	}
