287	fn app(session: Session) -> Router {
288	    Router::new()
289	        .route(
290	            "/{*key_expr}",
291	            get(subscribe_or_query)
292	                .post(subscribe_or_query)
293	                .put(publish)
294	                .patch(publish)
295	                .delete(publish),
296	        )
297	        .with_state(AppState { session })
298	        .layer(
299	            TraceLayer::new_for_http()
300	                .make_span_with(DefaultMakeSpan::new().include_headers(true))
301	                .on_request(DefaultOnRequest::new().level(Level::TRACE))
302	                .on_response(
303	                    DefaultOnResponse::new()
304	                        .level(Level::TRACE)
305	                        .include_headers(true),
306	                ),
307	        )
308	        .layer(
309	            CorsLayer::new()
310	                .allow_methods([
311	                    Method::GET,
312	                    Method::POST,
313	                    Method::PUT,
314	                    Method::PATCH,
315	                    Method::DELETE,
316	                ])
317	                .allow_origin(Any)
318	                .allow_credentials(false),
319	        )
320	        .layer(SetResponseHeaderLayer::overriding(
321	            header::ACCESS_CONTROL_ALLOW_ORIGIN,
322	            HeaderValue::from_static("*"),
323	        ))
324	}
