331	async fn subscribe(state: AppState, key_expr: KeyExpr<'static>) -> Response {
332	    let subscriber = match state.session.declare_subscriber(&key_expr).await {
333	        Ok(sub) => sub,
334	        Err(err) => return (StatusCode::INTERNAL_SERVER_ERROR, err.to_string()).into_response(),
335	    };
336	    struct SubscriberStream {
337	        stream: RecvStream<'static, Sample>,
338	        _subscriber: Subscriber<FifoChannelHandler<Sample>>,
339	    }
340	    impl Stream for SubscriberStream {
341	        type Item = Sample;
342	
343	        fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
344	            self.stream.poll_next_unpin(cx)
345	        }
346	    }
347	    let stream = SubscriberStream {
348	        stream: subscriber.handler().clone().into_stream(),
349	        _subscriber: subscriber,
350	    };
351	    Sse::new(stream.map(|sample| {
352	        Event::default()
353	            .event(sample.kind().to_string())
354	            .json_data(JSONSample::from(&sample))
355	    }))
356	    .into_response()
357	}
