359	async fn query(
360	    state: AppState,
361	    accept: Accept,
362	    key_expr: KeyExpr<'static>,
363	    encoding: Encoding,
364	    uri: Uri,
365	    body: ZBytes,
366	) -> Response {
367	    let parameters = Parameters::from(uri.query().unwrap_or_default());
368	    let consolidation = if parameters.time_range().is_some() {
369	        QueryConsolidation::from(zenoh::query::ConsolidationMode::None)
370	    } else {
371	        QueryConsolidation::from(zenoh::query::ConsolidationMode::Latest)
372	    };
373	    let mut query = state
374	        .session
375	        .get(Selector::borrowed(&key_expr, &parameters))
376	        .consolidation(consolidation)
377	        .with(flume::unbounded());
378	    if !body.is_empty() {
379	        query = query.payload(body).encoding(encoding);
380	    }
381	    match query.await {
382	        Ok(receiver) => match accept {
383	            Accept::Raw => match receiver.recv_async().await {
384	                Ok(reply) => {
385	                    let (encoding, payload) = match reply.result() {
386	                        Ok(sample) => (sample.encoding(), sample.payload()),
387	                        Err(err) => (err.encoding(), err.payload()),
388	                    };
389	                    let content_type = Some([(header::CONTENT_TYPE, encoding.to_string())])
390	                        .filter(|[(_, e)]| Mime::from_str(e).is_ok());
391	                    (content_type, payload.to_bytes().to_vec()).into_response()
392	                }
393	                Err(_) => StatusCode::OK.into_response(),
394	            },
395	            Accept::Html => {
396	                let mut html = "<dl>\n".to_string();
397	                while let Ok(reply) = receiver.recv_async().await {
398	                    let (key, payload) = match reply.result() {
399	                        Ok(sample) => (sample.key_expr().as_str(), sample.payload().to_bytes()),
400	                        Err(err) => ("ERROR", err.payload().to_bytes()),
401	                    };
402	                    let payload = String::from_utf8_lossy(&payload);
403	                    write!(&mut html, "<dt>{key}</dt>\n<dd>{payload}</dd>\n").unwrap();
404	                }
405	                Html(html + "</dl>\n").into_response()
406	            }
407	            Accept::Json => receiver
408	                .stream()
409	                .map(|reply| match reply.into_result() {
410	                    Ok(sample) => JSONSample::from(&sample),
411	                    Err(err) => JSONSample::new("ERROR", err.payload(), err.encoding(), None),
412	                })
413	                .collect::<Vec<JSONSample>>()
414	                .map(Json)
415	                .await
416	                .into_response(),
417	            _ => unreachable!(),
418	        },
419	        Err(err) => (StatusCode::INTERNAL_SERVER_ERROR, err.to_string()).into_response(),
420	    }
421	}
