423	async fn subscribe_or_query(
424	    State(state): State<AppState>,
425	    accept: Accept,
426	    KeyExprPath(key_expr): KeyExprPath,
427	    EncodingHeader(encoding): EncodingHeader,
428	    uri: Uri,
429	    ZBytesBody(body): ZBytesBody,
430	) -> Response {
431	    match accept {
432	        Accept::EventStream => subscribe(state, key_expr).await,
433	        accept => query(state, accept, key_expr, encoding, uri, body).await,
434	    }
435	}
