437	async fn publish(
438	    State(state): State<AppState>,
439	    method: Method,
440	    KeyExprPath(key_expr): KeyExprPath,
441	    EncodingHeader(encoding): EncodingHeader,
442	    ZBytesBody(bytes): ZBytesBody,
443	) -> Response {
444	    // @TODO: Define the right congestion control value
445	    let res = if method == Method::DELETE {
446	        state.session.delete(key_expr).await
447	    } else {
448	        state.session.put(key_expr, bytes).encoding(encoding).await
449	    };
450	    match res {
451	        Ok(_) => StatusCode::OK.into_response(),
452	        Err(err) => (StatusCode::INTERNAL_SERVER_ERROR, err.to_string()).into_response(),
453	    }
454	}
