456	pub async fn run(runtime: DynamicRuntime, addr: SocketAddr) -> ZResult<()> {
457	    // Try to initiate login.
458	    // Required in case of dynamic lib, otherwise no logs.
459	    // But cannot be done twice in case of static link.
460	    zenoh::init_log_from_env_or("error");
461	
462	    match tokio::try_join!(
463	        zenoh::session::init(runtime),
464	        TcpListener::bind(addr).map_err(Into::into)
465	    ) {
466	        Ok((session, listener)) => axum::serve(listener, app(session)).await?,
467	        Err(err) => {
468	            tracing::error!("Unable to start http server for REST: {:?}", err);
469	            return Err(err);
470	        }
471	    }
472	    Ok(())
473	}
