475	struct KeyExprPath(KeyExpr<'static>);
476	
477	impl FromRequestParts<AppState> for KeyExprPath {
478	    type Rejection = Response;
479	
480	    async fn from_request_parts(
481	        parts: &mut Parts,
482	        state: &AppState,
483	    ) -> Result<Self, Self::Rejection> {
484	        let Path(mut key_expr): Path<String> = Path::from_request_parts(parts, state)
485	            .await
486	            .map_err(IntoResponse::into_response)?;
487	        if let Some(suffix) = key_expr.strip_prefix("@/local") {
488	            if suffix.is_empty() || suffix.starts_with('/') {
489	                key_expr = format!("@/{zid}{suffix}", zid = state.session.zid());
490	            }
491	        }
492	        match KeyExpr::try_from(key_expr) {
493	            Ok(key_expr) => Ok(KeyExprPath(key_expr)),
494	            Err(err) => Err((StatusCode::BAD_REQUEST, err.to_string()).into_response()),
495	        }
496	    }
497	}
