499	struct EncodingHeader(Encoding);
500	
501	impl FromRequestParts<AppState> for EncodingHeader {
502	    type Rejection = Infallible;
503	
504	    async fn from_request_parts(
505	        parts: &mut Parts,
506	        _state: &AppState,
507	    ) -> Result<Self, Self::Rejection> {
508	        let encoding = match parts.headers.get(header::CONTENT_TYPE) {
509	            Some(h) => Encoding::from(String::from_utf8_lossy(h.as_bytes()).as_ref()),
510	            None => Encoding::default(),
511	        };
512	        Ok(EncodingHeader(encoding))
513	    }
514	}
