516	enum Accept {
517	    EventStream,
518	    Raw,
519	    Html,
520	    Json,
521	}
522	
523	impl FromRequestParts<AppState> for Accept {
524	    type Rejection = Infallible;
525	
526	    async fn from_request_parts(
527	        parts: &mut Parts,
528	        _state: &AppState,
529	    ) -> Result<Self, Self::Rejection> {
530	        let accept = match parts
531	            .headers
532	            .get(header::ACCEPT)
533	            .and_then(|h| h.to_str().ok()?.split(',').next()?.split(';').next())
534	        {
535	            Some("text/event-stream") => Accept::EventStream,
536	            _ if Parameters::from(parts.uri.query().unwrap_or_default()).contains_key(RAW_KEY) => {
537	                Accept::Raw
538	            }
539	            Some("text/html") => Accept::Html,
540	            _ => Accept::Json,
541	        };
542	        Ok(accept)
543	    }
544	}
