546	struct ZBytesBody(ZBytes);
547	
548	impl FromRequest<AppState> for ZBytesBody {
549	    type Rejection = (StatusCode, String);
550	
551	    async fn from_request(req: Request, _state: &AppState) -> Result<Self, Self::Rejection> {
552	        let mut stream = req.into_body().into_data_stream();
553	        let mut writer = ZBytes::writer();
554	        while let Some(bytes) = stream.next().await {
555	            match bytes {
556	                Ok(bytes) => writer.append(bytes.into()),
557	                Err(err) => return Err((StatusCode::INTERNAL_SERVER_ERROR, err.to_string())),
558	            }
559	        }
560	        Ok(ZBytesBody(writer.finish()))
561	    }
562	}
