115	    fn new(runtime: DynamicRuntime, config: PluginConfig) -> ZResult<Self> {
116	        // Try to initiate login.
117	        // Required in case of dynamic lib, otherwise no logs.
118	        // But cannot be done twice in case of static link.
119	        zenoh::init_log_from_env_or("error");
120	        let PluginConfig {
121	            name,
122	            backend_search_dirs,
123	            volumes,
