129	        let mut plugins_manager = PluginsManager::dynamic(lib_loader.clone(), BACKEND_LIB_PREFIX);
130	        plugins_manager.declare_static_plugin::<MemoryBackend, &str>(MEMORY_BACKEND_NAME, true);
131	
132	        let session = Arc::new(zenoh::session::init(runtime.clone()).wait()?);
133	
134	        // NOTE: All storage **must** have a timestamp associated with a Sample. Considering that it is possible to make
135	        //       a publication without associating a timestamp, that means that the node managing the storage (be it a
136	        //       Zenoh client / peer / router) has to add it.
137	        //
138	        //       If the `timestamping` configuration setting is disabled then there is no HLC associated with the
139	        //       Session. That eventually means that no timestamp can be generated which goes against the previous
140	        //       requirement.
141	        //
142	        //       Hence, in that scenario, we refuse to start the storage manager and any storage.
143	        if session.hlc().is_none() {
144	            tracing::error!(
145	                "Cannot start storage manager (and thus any storage) without the 'timestamping' \
146	                 setting enabled in the Zenoh configuration"
147	            );
148	            bail!("Cannot start storage manager, 'timestamping' is disabled in the configuration");
149	        }
150	
151	        // After this moment result should be only Ok. Failure of loading of one volume or storage should not affect others.
152	
153	        let mut new_self = StorageRuntimeInner {
154	            name,
155	            runtime,
156	            session,
157	            storages: Default::default(),
158	            plugins_manager,
159	        };
160	        new_self
161	            .spawn_volume(&VolumeConfig {
162	                name: MEMORY_BACKEND_NAME.into(),
163	                backend: None,
164	                paths: None,
165	                required: false,
166	                rest: Default::default(),
167	            })
168	            .map_or_else(
169	                |e| {
170	                    tracing::error!(
171	                        "Cannot spawn static volume '{}': {}",
172	                        MEMORY_BACKEND_NAME,
173	                        e
174	                    )
175	                },
176	                |_| (),
177	            );
178	        for volume in &volumes {
179	            new_self.spawn_volume(volume).map_or_else(
180	                |e| tracing::error!("Cannot spawn volume '{}': {}", volume.name(), e),
181	                |_| (),
182	            );
183	        }
184	        for storage in &storages {
185	            new_self.spawn_storage(storage).map_or_else(
186	                |e| tracing::error!("Cannot spawn storage '{}': {}", storage.name(), e),
187	                |_| (),
188	            );
189	        }
190	        Ok(new_self)
191	    }
192	    fn update<I: IntoIterator<Item = ConfigDiff>>(&mut self, diffs: I) -> ZResult<()> {
193	        for ref diff in diffs {
194	            match diff {
195	                ConfigDiff::DeleteVolume(volume) => self.kill_volume(&volume.name)?,
196	                ConfigDiff::AddVolume(volume) => {
197	                    self.spawn_volume(volume)?;
198	                }
199	                ConfigDiff::DeleteStorage(config) => self.kill_storage(config),
200	                ConfigDiff::AddStorage(config) => self.spawn_storage(config)?,
201	            }
202	        }
203	        Ok(())
204	    }
205	    fn kill_volume<T: AsRef<str>>(&mut self, name: T) -> ZResult<()> {
206	        let name = name.as_ref();
207	        tracing::info!("Killing volume '{}'", name);
208	        if let Some(storages) = self.storages.remove(name) {
209	            tokio::task::block_in_place(|| {
210	                TOKIO_RUNTIME.block_on(futures::future::join_all(
211	                    storages
212	                        .into_values()
213	                        .map(|s| async move { s.send(StorageMessage::Stop) }),
214	                ))
215	            });
216	        }
217	        self.plugins_manager
218	            .started_plugin_mut(name)
219	            .ok_or(format!("Cannot find volume '{name}' to stop it"))?
220	            .stop();
221	        Ok(())
222	    }
223	    fn spawn_volume(&mut self, config: &VolumeConfig) -> ZResult<()> {
224	        let volume_id = config.name();
225	        let backend_name = config.backend();
226	        tracing::info!(
227	            "Spawning volume '{}' with backend '{}'",
228	            volume_id,
229	            backend_name
230	        );
231	        let declared = if let Some(declared) = self.plugins_manager.plugin_mut(volume_id) {
232	            declared
233	        } else if let Some(paths) = config.paths() {
234	            self.plugins_manager.declare_dynamic_plugin_by_paths(
235	                backend_name,
236	                volume_id,
237	                paths,
238	                true,
239	            )?
240	        } else {
241	            self.plugins_manager
242	                .declare_dynamic_plugin_by_name(volume_id, backend_name, true)?
243	        };
244	        let loaded = declared
245	            .load()?
246	            .expect("Volumes should not be loaded if the storage-manager plugin is not loaded");
247	        loaded.start(config)?;
248	
249	        Ok(())
250	    }
251	    fn kill_storage(&mut self, config: &StorageConfig) {
252	        let volume = &config.volume_id;
253	        tracing::info!("Killing storage '{}' from volume '{}'", config.name, volume);
254	        if let Some(storages) = self.storages.get_mut(volume) {
255	            if let Some(storage) = storages.get_mut(&config.name) {
256	                tracing::debug!(
257	                    "Closing storage '{}' from volume '{}'",
258	                    config.name,
259	                    config.volume_id
260	                );
261	                // let _ = async_std::task::block_on(storage.send(StorageMessage::Stop));
262	                let _ = storage.send(StorageMessage::Stop); // TODO: was previously spawning a task. do we need that?
263	            }
264	        }
265	    }
266	    fn spawn_storage(&mut self, storage: &StorageConfig) -> ZResult<()> {
267	        let admin_key = self.status_key() + "/storages/" + &storage.name;
268	        let volume_id = storage.volume_id.clone();
269	        let backend = self
270	            .plugins_manager
271	            .started_plugin(&volume_id)
272	            .ok_or(format!(
273	                "Cannot find volume '{}' to spawn storage '{}'",
274	                volume_id, storage.name
275	            ))?;
276	        let storage_name = storage.name.clone();
277	        tracing::info!(
278	            "Spawning storage '{}' from volume '{}' with backend '{}'",
279	            storage_name,
280	            volume_id,
281	            backend.name()
282	        );
283	        let stopper = tokio::task::block_in_place(|| {
284	            TOKIO_RUNTIME.block_on(create_and_start_storage(
285	                admin_key,
286	                storage.clone(),
287	                backend.instance(),
288	                self.session.clone(),
289	            ))
290	        })?;
291	        self.storages
292	            .entry(volume_id)
293	            .or_default()
294	            .insert(storage_name, stopper);
295	        Ok(())
296	    }
297	}
