320	    fn config_checker(
321	        &self,
322	        _: &str,
323	        old: &JsonKeyValueMap,
324	        new: &JsonKeyValueMap,
325	    ) -> ZResult<Option<JsonKeyValueMap>> {
326	        let old: serde_json::Map<String, serde_json::Value> = old.into();
