341	    fn adminspace_getter<'a>(
342	        &'a self,
343	        key_expr: &'a KeyExpr<'a>,
344	        plugin_status_key: &str,
345	    ) -> ZResult<Vec<Response>> {
346	        let mut responses = Vec::new();
347	        let mut key = String::from(plugin_status_key);
348	        // TODO: to be removed when "__version__" is implemented in admin space
349	        with_extended_string(&mut key, &["/version"], |key| {
350	            if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
351	                responses.push(Response::new(
352	                    key.clone(),
353	                    StoragesPlugin::PLUGIN_VERSION.into(),
354	                ))
355	            }
356	        });
357	        let guard = self.0.lock().unwrap();
358	        with_extended_string(&mut key, &["/volumes/"], |key| {
359	            for plugin in guard.plugins_manager.started_plugins_iter() {
360	                with_extended_string(key, &[plugin.id()], |key| {
361	                    with_extended_string(key, &["/__path__"], |key| {
362	                        if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
363	                            responses.push(Response::new(key.clone(), plugin.path().into()))
364	                        }
365	                    });
366	                    if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
367	                        responses.push(Response::new(
368	                            key.clone(),
369	                            plugin.instance().get_admin_status().into(),
370	                        ))
371	                    }
372	                });
373	            }
374	        });
375	        with_extended_string(&mut key, &["/storages/"], |key| {
376	            for storages in guard.storages.values() {
377	                for (storage, handle) in storages {
378	                    with_extended_string(key, &[storage], |key| {
379	                        if keyexpr::new(key.as_str()).unwrap().intersects(key_expr) {
380	                            if let Some(value) = tokio::task::block_in_place(|| {
381	                                TOKIO_RUNTIME.block_on(async {
382	                                    let (tx, mut rx) = tokio::sync::mpsc::channel(1);
383	                                    let _ = handle.send(StorageMessage::GetStatus(tx));
384	                                    rx.recv().await
385	                                })
386	                            }) {
387	                                responses.push(Response::new(key.clone(), value))
388	                            }
389	                        }
390	                    })
391	                }
392	            }
393	        });
394	        Ok(responses)
395	    }
396	}
