401	fn with_extended_string<R, F: FnMut(&mut String) -> R>(
402	    prefix: &mut String,
403	    suffixes: &[&str],
404	    mut closure: F,
405	) -> R {
406	    let prefix_len = prefix.len();
407	    for suffix in suffixes {
408	        prefix.push_str(suffix);
409	    }
410	    let result = closure(prefix);
411	    prefix.truncate(prefix_len);
412	    result
413	}
