415	/// Returns the key expression stripped of the provided prefix.
416	///
417	/// If no prefix is provided this function returns the key expression untouched.
418	///
419	/// If `None` is returned, it indicates that the key expression is equal to the prefix.
420	///
421	/// This function will internally call [strip_prefix], see its documentation for possible outcomes.
422	///
423	/// # Errors
424	///
425	/// This function will return an error if:
426	/// - The provided prefix contains a wildcard.
427	///   NOTE: The configuration of a Storage is checked and will reject any prefix that contains a
428	///   wildcard. In theory, this error should never occur.
429	/// - The key expression is not prefixed by the provided prefix.
430	/// - The resulting stripped key is not a valid key expression (this should, in theory, never
431	///   happen).
432	///
433	/// [strip_prefix]: zenoh::key_expr::keyexpr::strip_prefix()
434	pub fn strip_prefix(
435	    maybe_prefix: Option<&OwnedKeyExpr>,
436	    key_expr: &KeyExpr<'_>,
437	) -> ZResult<Option<OwnedKeyExpr>> {
438	    match maybe_prefix {
439	        None => Ok(Some(key_expr.clone().into())),
440	        Some(prefix) => {
441	            if prefix.is_wild() {
442	                bail!(
443	                    "Prefix < {} > contains a wild character (\"**\" or \"*\")",
444	                    prefix
445	                );
446	            }
447	
448	            // `key_expr.strip_prefix` returns empty vec if `key_expr == prefix`,
449	            // but also returns empty vec if `prefix` is not a prefix to `key_expr`.
450	            // First case needs to be handled before calling `key_expr.strip_prefix`
451	            if key_expr.as_str().eq(prefix.as_str()) {
452	                return Ok(None);
453	            }
454	
455	            match key_expr.strip_prefix(prefix).as_slice() {
456	                // NOTE: `stripped_key_expr.is_empty()` should be impossible as "" is not a valid key expression
457	                [stripped_key_expr] => OwnedKeyExpr::from_str(stripped_key_expr).map(Some),
458	                _ => bail!("Failed to strip prefix < {} > from: {}", prefix, key_expr),
459	            }
460	        }
461	    }
462	}
463	
464	/// Returns the key with an additional prefix, if both were provided.
465	///
466	/// If no prefix is provided, this function returns `maybe_stripped_key`.
467	///
468	/// If no key is provided, this function returns the `maybe_prefix`.
469	///
470	/// If a prefix is provided, this function returns the concatenation of both.
471	///
472	/// # Error
473	///
474	/// This function will return an error if both `maybe_prefix` and `maybe_stripped_key` are equal to
475	/// `None`. This situation can happen if (i) the "backend" associated to a Storage is first started
476	/// with a `strip_prefix` set to some value, (ii) a key equal to the `strip_prefix` is published
477	/// (hence storing `None`) then (iii) the Storage is stopped and the "backend" is associated to
478	/// another Storage without a `strip_prefix` configured.
479	pub fn prefix(
480	    maybe_prefix: Option<&OwnedKeyExpr>,
481	    maybe_stripped_key: Option<&OwnedKeyExpr>,
482	) -> ZResult<OwnedKeyExpr> {
483	    match (maybe_prefix, maybe_stripped_key) {
484	        (Some(prefix), Some(stripped_key)) => Ok(prefix / stripped_key),
485	        (Some(prefix), None) => Ok(prefix.clone()),
486	        (None, Some(key)) => Ok(key.clone()),
487	        (None, None) => bail!("Fatal internal error: empty prefix with empty key"),
488	    }
489	}
