156	/// Capability of a storage indicates the guarantees of the storage
157	/// It is used by the storage manager to take decisions on the trade-offs to ensure correct performance
158	#[derive(Debug, Clone, PartialEq, Eq)]
159	pub struct Capability {
160	    pub persistence: Persistence,
161	    pub history: History,
162	}
163	
164	/// Persistence is the guarantee expected from a storage in case of failures
165	/// If a storage is marked Persistent::Durable, if it restarts after a crash, it will still have all the values that were saved.
166	/// This will include also persisting the metadata that Zenoh stores for the updates.
167	/// If a storage is marked Persistent::Volatile, the storage will not have any guarantees on its content after a crash.
168	/// This option should be used only if the storage is considered to function as a cache.
169	#[derive(Debug, Clone, PartialEq, Eq)]
170	pub enum Persistence {
171	    Volatile, //default
172	    Durable,
173	}
174	
175	/// History is the number of values that the backend is expected to save per key
176	/// History::Latest saves only the latest value per key
177	/// History::All saves all the values including historical values
178	#[derive(Debug, Clone, PartialEq, Eq)]
179	pub enum History {
180	    Latest, //default
181	    All,
182	}
