223	/// Trait to be implemented by a Storage.
224	#[async_trait]
225	pub trait Storage: Send + Sync {
226	    /// Returns the status that will be sent as a reply to a query
227	    /// on the administration space for this storage.
228	    fn get_admin_status(&self) -> JsonValue;
229	
230	    /// Function called for each incoming data ([`Sample`](zenoh::sample::Sample)) to be stored in this storage.
231	    /// A key can be `None` if it matches the `strip_prefix` exactly.
232	    /// In order to avoid data loss, the storage must store the `value` and `timestamp` associated with the `None` key
233	    /// in a manner suitable for the given backend technology
234	    async fn put(
235	        &mut self,
236	        key: Option<OwnedKeyExpr>,
237	        payload: ZBytes,
238	        encoding: Encoding,
239	        timestamp: Timestamp,
240	    ) -> ZResult<StorageInsertionResult>;
241	
242	    /// Function called for each incoming delete request to this storage.
243	    /// A key can be `None` if it matches the `strip_prefix` exactly.
244	    /// In order to avoid data loss, the storage must delete the entry corresponding to the `None` key
245	    /// in a manner suitable for the given backend technology
246	    async fn delete(
247	        &mut self,
248	        key: Option<OwnedKeyExpr>,
249	        timestamp: Timestamp,
250	    ) -> ZResult<StorageInsertionResult>;
251	
252	    /// Function to retrieve the sample associated with a single key.
253	    /// A key can be `None` if it matches the `strip_prefix` exactly.
254	    /// In order to avoid data loss, the storage must retrieve the `value` and `timestamp` associated with the `None` key
255	    /// in a manner suitable for the given backend technology
256	    async fn get(
257	        &mut self,
258	        key: Option<OwnedKeyExpr>,
259	        parameters: &str,
260	    ) -> ZResult<Vec<StoredData>>;
