43	const MAX_BLOCK_THREAD_NUM: usize = 50;
44	lazy_static::lazy_static! {
45	    // The global runtime is used in the dynamic plugins, which we can't get the current runtime
46	    static ref TOKIO_RUNTIME: tokio::runtime::Runtime = tokio::runtime::Builder::new_multi_thread()
47	               .worker_threads(WORKER_THREAD_NUM)
48	               .max_blocking_threads(MAX_BLOCK_THREAD_NUM)
49	               .enable_all()
