53	#[inline(always)]
54	fn spawn_runtime(task: impl Future<Output = ()> + Send + 'static) {
55	    // Check whether able to get the current runtime
56	    match tokio::runtime::Handle::try_current() {
57	        Ok(rt) => {
58	            // Able to get the current runtime (standalone binary), spawn on the current runtime
59	            rt.spawn(task);
60	        }
61	        Err(_) => {
62	            // Unable to get the current runtime (dynamic plugins), spawn on the global runtime
63	            TOKIO_RUNTIME.spawn(task);
64	        }
65	    }
66	}
