76	// A default selector for this example of storage plugin (in case the config doesn't set it)
77	// This plugin will subscribe to this selector and declare a queryable with this selector
78	const DEFAULT_SELECTOR: &str = "demo/example/**";
79	
80	impl ZenohPlugin for ExamplePlugin {}
81	impl Plugin for ExamplePlugin {
82	    type StartArgs = DynamicRuntime;
83	    type Instance = zenoh::internal::plugins::RunningPlugin;
84	
85	    // A mandatory const to define, in case of the plugin is built as a standalone executable
86	    const DEFAULT_NAME: &'static str = "example";
87	    const PLUGIN_VERSION: &'static str = plugin_version!();
88	    const PLUGIN_LONG_VERSION: &'static str = plugin_long_version!();
89	
90	    // The first operation called by zenohd on the plugin
91	    fn start(name: &str, runtime: &Self::StartArgs) -> ZResult<Self::Instance> {
92	        let config = runtime.get_config().get_plugin_config(name).unwrap();
93	        let map_cfg = config.as_object().unwrap();
94	        // get the plugin's config details from self_cfg Map (here the "storage-selector" property)
95	        let selector: KeyExpr = match map_cfg.get("storage-selector") {
96	            Some(serde_json::Value::String(s)) => KeyExpr::try_from(s)?,
97	            None => KeyExpr::try_from(DEFAULT_SELECTOR).unwrap(),
98	            _ => {
99	                bail!("storage-selector is a mandatory option for {}", name)
100	            }
101	        }
102	        .clone()
103	        .into_owned();
104	
105	        // a flag to end the plugin's loop when the plugin is removed from the config
106	        let flag = Arc::new(AtomicBool::new(true));
107	        spawn_runtime(run(runtime.clone(), selector, flag.clone()));
108	        // return a RunningPlugin to zenohd
109	        Ok(Box::new(RunningPlugin(Arc::new(Mutex::new(
110	            RunningPluginInner {
111	                flag,
112	                name: name.into(),
113	                runtime: runtime.clone(),
114	            },
115	        )))))
116	    }
117	}
118	
119	// An inner-state for the RunningPlugin
120	struct RunningPluginInner {
121	    flag: Arc<AtomicBool>,
122	    name: String,
123	    runtime: DynamicRuntime,
124	}
125	// The RunningPlugin struct implementing the RunningPluginTrait trait
126	#[derive(Clone)]
127	struct RunningPlugin(Arc<Mutex<RunningPluginInner>>);
128	
129	impl PluginControl for RunningPlugin {}
130	
131	impl RunningPluginTrait for RunningPlugin {
132	    fn config_checker(
133	        &self,
134	        path: &str,
135	        old: &JsonKeyValueMap,
136	        new: &JsonKeyValueMap,
137	    ) -> ZResult<Option<JsonKeyValueMap>> {
138	        let old: serde_json::Map<String, serde_json::Value> = old.into();
139	        let new: serde_json::Map<String, serde_json::Value> = new.into();
140	        let mut guard = zlock!(&self.0);
141	        const STORAGE_SELECTOR: &str = "storage-selector";
142	        if path == STORAGE_SELECTOR || path.is_empty() {
143	            match (old.get(STORAGE_SELECTOR), new.get(STORAGE_SELECTOR)) {
144	                (Some(serde_json::Value::String(os)), Some(serde_json::Value::String(ns)))
145	                    if os == ns => {}
146	                (_, Some(serde_json::Value::String(selector))) => {
147	                    guard.flag.store(false, Relaxed);
148	                    guard.flag = Arc::new(AtomicBool::new(true));
149	                    match KeyExpr::try_from(selector.clone()) {
150	                        Err(e) => tracing::error!("{}", e),
151	                        Ok(selector) => {
152	                            spawn_runtime(run(guard.runtime.clone(), selector, guard.flag.clone()));
153	                        }
154	                    }
155	                    return Ok(None);
156	                }
157	                (_, None) => {
158	                    guard.flag.store(false, Relaxed);
159	                }
160	                _ => {
161	                    bail!("storage-selector for {} must be a string", &guard.name)
162	                }
163	            }
164	        }
165	        bail!("unknown option {} for {}", path, guard.name)
166	    }
167	}
168	
169	// If the plugin is dropped, set the flag to false to end the loop
170	impl Drop for RunningPlugin {
171	    fn drop(&mut self) {
172	        zlock!(self.0).flag.store(false, Relaxed);
173	    }
174	}
175	
176	async fn run(runtime: DynamicRuntime, selector: KeyExpr<'_>, flag: Arc<AtomicBool>) {
177	    zenoh_util::init_log_from_env_or("error");
178	
179	    // create a zenoh Session that shares the same Runtime than zenohd
180	    let session = zenoh::session::init(runtime).await.unwrap();
181	
182	    // the HasMap used as a storage by this example of storage plugin
183	    let mut stored: HashMap<String, Sample> = HashMap::new();
184	
185	    debug!("Run example-plugin with storage-selector={}", selector);
186	
187	    // This storage plugin subscribes to the selector and will store in HashMap the received samples
188	    debug!("Create Subscriber on {}", selector);
189	    let sub = session.declare_subscriber(&selector).await.unwrap();
190	
191	    // This storage plugin declares a Queryable that will reply to queries with the samples stored in the HashMap
192	    debug!("Create Queryable on {}", selector);
193	    let queryable = session.declare_queryable(&selector).await.unwrap();
194	
195	    // Plugin's event loop, while the flag is true
196	    while flag.load(Relaxed) {
197	        select!(
198	            // on sample received by the Subscriber
199	            sample = sub.recv_async() => {
200	                let sample = sample.unwrap();
201	                let payload = sample.payload().try_to_string().unwrap_or_else(|e| e.to_string().into());
202	                info!("Received data ('{}': '{}')", sample.key_expr(), payload);
203	                stored.insert(sample.key_expr().to_string(), sample);
204	            },
205	            // on query received by the Queryable
206	            query = queryable.recv_async() => {
207	                let query = query.unwrap();
208	                info!("Handling query '{}'", query.selector());
209	                for (key_expr, sample) in stored.iter() {
210	                    if query.key_expr().intersects(unsafe{keyexpr::from_str_unchecked(key_expr)}) {
211	                        query.reply_sample(sample.clone()).await.unwrap();
212	                    }
213	                }
214	            }
215	        );
216	    }
217	}
