80	#[async_trait]
81	impl Storage for ExampleStorage {
82	    fn get_admin_status(&self) -> JsonValue {
83	        serde_json::Value::Null.into()
84	    }
85	    async fn put(
86	        &mut self,
87	        key: Option<OwnedKeyExpr>,
88	        payload: ZBytes,
89	        encoding: Encoding,
90	        timestamp: Timestamp,
91	    ) -> ZResult<StorageInsertionResult> {
92	        let mut map = self.map.write().await;
93	        match map.entry(key) {
94	            Entry::Occupied(mut e) => {
95	                e.insert(StoredData {
96	                    payload,
97	                    encoding,
98	                    timestamp,
99	                });
100	                return Ok(StorageInsertionResult::Replaced);
101	            }
102	            Entry::Vacant(e) => {
103	                e.insert(StoredData {
104	                    payload,
105	                    encoding,
106	                    timestamp,
107	                });
108	                return Ok(StorageInsertionResult::Inserted);
109	            }
110	        }
111	    }
112	
113	    async fn delete(
114	        &mut self,
115	        key: Option<OwnedKeyExpr>,
116	        _timestamp: Timestamp,
117	    ) -> ZResult<StorageInsertionResult> {
118	        self.map.write().await.remove_entry(&key);
119	        Ok(StorageInsertionResult::Deleted)
120	    }
121	
122	    async fn get(
123	        &mut self,
124	        key: Option<OwnedKeyExpr>,
125	        _parameters: &str,
126	    ) -> ZResult<Vec<StoredData>> {
127	        match self.map.read().await.get(&key) {
128	            Some(v) => Ok(vec![v.clone()]),
129	            None => Err(format!("Key {key:?} is not present").into()),
130	        }
131	    }
132	
133	    async fn get_all_entries(&self) -> ZResult<Vec<(Option<OwnedKeyExpr>, Timestamp)>> {
134	        let map = self.map.read().await;
135	        let mut result = Vec::with_capacity(map.len());
136	        for (k, v) in map.iter() {
137	            result.push((k.clone(), v.timestamp));
138	        }
139	        Ok(result)
140	    }
141	}
