22	pub(crate) fn load_plugin(
23	    plugin_mgr: &mut PluginsManager,
24	    name: &str,
25	    id: &str,
26	    paths: &Option<Vec<String>>,
27	    required: bool,
28	) -> ZResult<()> {
29	    let declared = if let Some(declared) = plugin_mgr.plugin_mut(name) {
30	        tracing::warn!("Plugin `{}` was already declared", declared.id());
31	        declared
32	    } else if let Some(paths) = paths {
33	        plugin_mgr.declare_dynamic_plugin_by_paths(name, id, paths, required)?
34	    } else {
35	        plugin_mgr.declare_dynamic_plugin_by_name(id, name, required)?
36	    };
37	
38	    if let Some(loaded) = declared.loaded_mut() {
39	        tracing::warn!(
40	            "Plugin `{}` was already loaded from {}",
41	            loaded.id(),
42	            loaded.path()
43	        );
44	    } else {
45	        let _ = declared.load()?;
46	    };
47	    Ok(())
48	}
