50	pub(crate) fn load_plugins(config: &Config) -> PluginsManager {
51	    let mut manager = PluginsManager::dynamic(config.libloader(), PLUGIN_PREFIX.to_string());
52	    // Static plugins are to be added here, with `.add_static::<PluginType>()`
53	    for plugin_load in config.plugins().load_requests() {
54	        let PluginLoad {
55	            id,
56	            name,
57	            paths,
58	            required,
59	        } = plugin_load;
60	        tracing::info!(
61	            "Loading {req} plugin \"{id}\"",
62	            req = if required { "required" } else { "" }
63	        );
64	        if let Err(e) = load_plugin(&mut manager, &name, &id, &paths, required) {
65	            if required {
66	                panic!("Plugin load failure: {e}")
67	            } else {
68	                tracing::error!("Plugin load failure: {e}")
69	            }
70	        }
71	    }
72	    manager
73	}
74	
75	pub(crate) fn start_plugins(runtime: &Runtime) {
76	    let mut manager = runtime.plugins_manager();
77	    let dynamic_runtime = runtime.clone().into();
78	    for plugin in manager.loaded_plugins_iter_mut() {
79	        let required = plugin.required();
80	        tracing::info!(
81	            "Starting {req} plugin \"{name}\"",
82	            req = if required { "required" } else { "" },
83	            name = plugin.id()
84	        );
85	        match plugin.start(&dynamic_runtime) {
86	            Ok(_) => {
87	                tracing::info!(
88	                    "Successfully started plugin {} from {:?}",
89	                    plugin.id(),
90	                    plugin.path()
91	                );
92	            }
93	            Err(e) => {
94	                let report = match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| e.to_string())) {
95	                        Ok(s) => s,
96	                        Err(_) => panic!("Formatting the error from plugin {} ({:?}) failed, this is likely due to ABI instability.\r\nMake sure your plugin was built with the same version of cargo as zenohd", plugin.name(), plugin.path()),
97	                    };
98	                if required {
99	                    panic!(
100	                        "Plugin \"{}\" failed to start: {}",
101	                        plugin.id(),
102	                        if report.is_empty() {
103	                            "no details provided"
104	                        } else {
105	                            report.as_str()
106	                        }
107	                    );
108	                } else {
109	                    tracing::error!(
110	                        "Required plugin \"{}\" failed to start: {}",
111	                        plugin.id(),
112	                        if report.is_empty() {
113	                            "no details provided"
114	                        } else {
115	                            report.as_str()
116	                        }
117	                    );
118	                }
119	            }
120	        }
121	        tracing::info!("Finished loading plugins");
122	    }
123	}
